// PATCH: Cover subscription cadence when split children are present locally.

func TestBuildSubscriptionResultsIgnoresSplitChildren(t *testing.T) {
	txs := []localTransaction{
		subscriptionTestTx("parent-1", "Netflix", 100, "2026-01-01", ""),
		subscriptionTestTx("child-1a", "Netflix", 60, "2026-01-01", "parent-1"),
		subscriptionTestTx("child-1b", "Netflix", 40, "2026-01-01", "parent-1"),
		subscriptionTestTx("parent-2", "Netflix", 100, "2026-02-01", ""),
		subscriptionTestTx("child-2a", "Netflix", 60, "2026-02-01", "parent-2"),
		subscriptionTestTx("child-2b", "Netflix", 40, "2026-02-01", "parent-2"),
		subscriptionTestTx("parent-3", "Netflix", 100, "2026-03-01", ""),
		subscriptionTestTx("child-3a", "Netflix", 60, "2026-03-01", "parent-3"),
		subscriptionTestTx("child-3b", "Netflix", 40, "2026-03-01", "parent-3"),
	}

	results := buildSubscriptionResults(txs, 3, false)
	if len(results) != 1 {
		t.Fatalf("results = %+v, want one subscription", results)
	}
	got := results[0]
	if got.PayeeNormalized != "netflix" || got.Occurrences != 3 || got.Cadence != "monthly" || got.AvgAmount != 100 {
		t.Fatalf("subscription result = %+v, want monthly Netflix from parent charges", got)
	}
}

