func subscriptionTestTx(id, payee string, amount float64, dateString, splitParentID string) localTransaction {
	date, err := time.Parse("2006-01-02", dateString)
	if err != nil {
		panic(err)
	}
	return localTransaction{
		ID:              id,
		Payee:           payee,
		PayeeNormalized: normalizeLocalPayee(payee),
		Amount:          amount,
		Date:            date,
		DateString:      dateString,
		SplitParentID:   splitParentID,
	}
}

func subscriptionTestGroupChild(id, payee string, amount float64, dateString, groupParentID string) localTransaction {
	tx := subscriptionTestTx(id, payee, amount, dateString, "")
	tx.GroupParentID = groupParentID
	return tx
}
